const checkpoints = [];
const programs = JSON.parse(localStorage.getItem('after_school_programs') || '[]');
const favorites = JSON.parse(localStorage.getItem('program_favorites') || '[]');
function parseTimeToMinutes(timeStr) {
  if (!timeStr || typeof timeStr !== 'string') return null;
  const match = timeStr.trim().match(/^(\d{1,2}):(\d{2})\s*([AaPp][Mm])$/);
  if (!match) return null;
  let hours = parseInt(match[1], 10);
  const minutes = parseInt(match[2], 10);
  const period = match[3].toUpperCase();
  if (period === 'PM' && hours < 12) hours += 12;
  if (period === 'AM' && hours === 12) hours = 0;
  return hours * 60 + minutes;
}
const maxEndMinutes = parseTimeToMinutes('4:30 PM');
const qualifyingPrograms = programs.filter(p => {
  if (!p || !p.is_active) return false;
  const grades = Array.isArray(p.grade_levels) ? p.grade_levels : [];
  if (!grades.includes('fourth_grade')) return false;
  if (p.category !== 'math_science') return false;
  const isFree = p.fee_frequency === 'free';
  const feeAmount = isFree ? 0 : (p.fee_amount || 0);
  if (!isFree && p.fee_frequency !== 'per_month') return false;
  if (feeAmount > 40) return false;
  const endMins = parseTimeToMinutes(p.end_time);
  if (endMins == null || endMins > maxEndMinutes) return false;
  return true;
});
let earliestProgram = null;
if (qualifyingPrograms.length > 0) {
  earliestProgram = qualifyingPrograms.reduce((best, p) => {
    if (!best) return p;
    const bestStart = parseTimeToMinutes(best.start_time);
    const pStart = parseTimeToMinutes(p.start_time);
    if (pStart == null) return best;
    if (bestStart == null || pStart < bestStart) return p;
    return best;
  }, null);
}
const favoriteProgramIds = favorites.map(f => f && f.program_id).filter(id => !!id);
const savedQualifyingIds = qualifyingPrograms
  .map(p => p.id)
  .filter(id => favoriteProgramIds.includes(id));
// CP1 (0.4): User saved at least one qualifying program that matches all criteria
checkpoints.push({ passed: savedQualifyingIds.length >= 1, weight: 0.4 });
// CP2 (0.6): User saved the earliest-start qualifying program
const savedEarliest = !!(earliestProgram && favoriteProgramIds.includes(earliestProgram.id));
checkpoints.push({ passed: savedEarliest, weight: 0.6 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const menuWeeks = JSON.parse(localStorage.getItem('menu_weeks') || '[]');
const dailyEntries = JSON.parse(localStorage.getItem('daily_menu_entries') || '[]');
const menuItems = JSON.parse(localStorage.getItem('menu_items') || '[]');
const mealPlanWeeks = JSON.parse(localStorage.getItem('meal_plan_weeks') || '[]');
const mealPlanEntries = JSON.parse(localStorage.getItem('meal_plan_entries') || '[]');
// Find the target menu week by label
const targetWeek = menuWeeks.find(w => w && w.label === 'Week of March 9');
let targetTriplet = [];
if (targetWeek) {
  const weekEntries = dailyEntries.filter(e => e && e.menu_week_id === targetWeek.id && e.meal_type === 'lunch' && e.is_primary_entree);
  const vegNutEntries = weekEntries.filter(e => {
    const item = menuItems.find(m => m && m.id === e.menu_item_id);
    if (!item) return false;
    return item.item_type === 'entree' && item.is_vegetarian && item.is_nut_free;
  });
  vegNutEntries.sort((a, b) => {
    const da = new Date(a.date).getTime();
    const db = new Date(b.date).getTime();
    return da - db;
  });
  const seenDates = new Set();
  const uniqueByDay = [];
  for (const e of vegNutEntries) {
    const dKey = e.date;
    if (!seenDates.has(dKey)) {
      seenDates.add(dKey);
      uniqueByDay.push(e);
    }
  }
  targetTriplet = uniqueByDay.slice(0, 3).map(e => ({ date: e.date, menu_item_id: e.menu_item_id }));
}
let qualifyingCount = 0;
if (targetWeek && targetTriplet.length > 0) {
  const relatedMealPlanWeeks = mealPlanWeeks.filter(mpw => mpw && mpw.menu_week_id === targetWeek.id);
  const relatedMealPlanWeekIds = relatedMealPlanWeeks.map(mpw => mpw.id);
  const relatedEntries = mealPlanEntries.filter(me => me && relatedMealPlanWeekIds.includes(me.meal_plan_week_id));
  const matches = targetTriplet.filter(t => relatedEntries.some(me => me.menu_item_id === t.menu_item_id && me.date === t.date));
  qualifyingCount = matches.length;
}
// CP1 (0.2): At least 1 of the earliest three qualifying veg/nut-free primary lunches is planned
checkpoints.push({ passed: targetTriplet.length >= 1 && qualifyingCount >= 1, weight: 0.2 });
// CP2 (0.3): At least 2 of the earliest three qualifying lunches are planned
checkpoints.push({ passed: targetTriplet.length >= 2 && qualifyingCount >= 2, weight: 0.3 });
// CP3 (0.5): All first 3 earliest qualifying lunches are planned
checkpoints.push({ passed: targetTriplet.length >= 3 && qualifyingCount >= 3, weight: 0.5 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const routes = JSON.parse(localStorage.getItem('bus_routes') || '[]');
const savedRoutes = JSON.parse(localStorage.getItem('saved_routes') || '[]');
function parseTimeToMinutes(timeStr) {
  if (!timeStr || typeof timeStr !== 'string') return null;
  const match = timeStr.trim().match(/^(\d{1,2}):(\d{2})\s*([AaPp][Mm])$/);
  if (!match) return null;
  let hours = parseInt(match[1], 10);
  const minutes = parseInt(match[2], 10);
  const period = match[3].toUpperCase();
  if (period === 'PM' && hours < 12) hours += 12;
  if (period === 'AM' && hours === 12) hours = 0;
  return hours * 60 + minutes;
}
const cutoff = parseTimeToMinutes('7:45 AM');
const qualifyingRoutes = routes.filter(r => {
  if (!r || !r.is_active) return false;
  if (r.grade_range !== 'k_5_elementary') return false;
  const streets = Array.isArray(r.served_streets) ? r.served_streets : [];
  const hasOak = streets.some(s => (s || '').toLowerCase().includes('oak street'));
  if (!hasOak) return false;
  const arrMins = parseTimeToMinutes(r.arrival_time_at_school);
  if (arrMins == null || arrMins >= cutoff) return false;
  return true;
});
let earliestRoute = null;
if (qualifyingRoutes.length > 0) {
  earliestRoute = qualifyingRoutes.reduce((best, r) => {
    if (!best) return r;
    const bestArr = parseTimeToMinutes(best.arrival_time_at_school);
    const rArr = parseTimeToMinutes(r.arrival_time_at_school);
    if (rArr == null) return best;
    if (bestArr == null || rArr < bestArr) return r;
    return best;
  }, null);
}
const savedRouteIds = savedRoutes.map(sr => sr && sr.bus_route_id).filter(id => !!id);
const savedQualifyingIds = qualifyingRoutes
  .map(r => r.id)
  .filter(id => savedRouteIds.includes(id));
// CP1 (0.4): User saved at least one qualifying Oak Street K-5 route arriving before 7:45 AM
checkpoints.push({ passed: savedQualifyingIds.length >= 1, weight: 0.4 });
// CP2 (0.6): User saved the earliest-arriving qualifying route
const savedEarliest = !!(earliestRoute && savedRouteIds.includes(earliestRoute.id));
checkpoints.push({ passed: savedEarliest, weight: 0.6 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const events = JSON.parse(localStorage.getItem('events') || '[]');
const savedEvents = JSON.parse(localStorage.getItem('saved_events') || '[]');
function minutesUtc(dateStr) {
  const d = new Date(dateStr);
  return d.getUTCHours() * 60 + d.getUTCMinutes();
}
const startWindow = 17 * 60; // 5:00 PM
const endWindow = 20 * 60;   // 8:00 PM
const qualifyingEvents = events.filter(ev => {
  if (!ev || !ev.start_datetime) return false;
  const d = new Date(ev.start_datetime);
  const year = d.getUTCFullYear();
  const month = d.getUTCMonth() + 1; // 1-12
  if (year !== 2026 || month !== 4) return false;
  if (ev.audience !== 'first_grade_families') return false;
  if (ev.is_all_day) return false;
  const mins = minutesUtc(ev.start_datetime);
  if (mins < startWindow || mins > endWindow) return false;
  return true;
});
qualifyingEvents.sort((a, b) => new Date(a.start_datetime).getTime() - new Date(b.start_datetime).getTime());
const targetEvents = qualifyingEvents.slice(0, 2);
const savedEventIds = savedEvents.map(se => se && se.event_id).filter(id => !!id);
const savedTargetCount = targetEvents.filter(ev => savedEventIds.includes(ev.id)).length;
// CP1 (0.4): User saved at least one of the first two qualifying April evening events for 1st-grade families
checkpoints.push({ passed: targetEvents.length >= 1 && savedTargetCount >= 1, weight: 0.4 });
// CP2 (0.6): User saved both of the first two qualifying events
checkpoints.push({ passed: targetEvents.length >= 2 && savedTargetCount >= 2, weight: 0.6 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkouts = [];
// alias to stay consistent with earlier naming
const checkpoints = checkouts;
const staff = JSON.parse(localStorage.getItem('staff_members') || '[]');
const messages = JSON.parse(localStorage.getItem('teacher_messages') || '[]');
const mathThirdTeachers = staff.filter(s => {
  if (!s || !s.is_teacher) return false;
  const grades = Array.isArray(s.grade_levels) ? s.grade_levels : [];
  if (!grades.includes('third_grade')) return false;
  if (s.primary_subject !== 'math') return false;
  return true;
});
let topTeacher = null;
if (mathThirdTeachers.length > 0) {
  topTeacher = mathThirdTeachers.reduce((best, s) => {
    if (!best) return s;
    const bestYears = best.years_of_experience || 0;
    const sYears = s.years_of_experience || 0;
    return sYears > bestYears ? s : best;
  }, null);
}
let msgsToTop = [];
let msgsToTopWithPhrase = [];
if (topTeacher) {
  msgsToTop = messages.filter(m => m && m.staff_member_id === topTeacher.id);
  msgsToTopWithPhrase = msgsToTop.filter(m => {
    const body = (m.message_body || '').toLowerCase();
    return body.includes('math homework expectations');
  });
}
// CP1 (0.4): At least one message sent via the form to the most experienced 3rd-grade math teacher
checkpoints.push({ passed: topTeacher != null && msgsToTop.length >= 1, weight: 0.4 });
// CP2 (0.6): At least one such message explicitly mentions 'math homework expectations'
checkpoints.push({ passed: topTeacher != null && msgsToTopWithPhrase.length >= 1, weight: 0.6 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const sections = JSON.parse(localStorage.getItem('policy_sections') || '[]');
const bookmarks = JSON.parse(localStorage.getItem('bookmarks') || '[]');
const qualifyingSections = sections.filter(s => {
  if (!s) return false;
  if (s.grade_level !== 'second_grade') return false;
  if (s.section_key !== 'homework_time_guidelines') return false;
  if (s.nightly_homework_minutes_limit !== 30) return false;
  return true;
});
const qualifyingIds = qualifyingSections.map(s => s.id);
const bookmarkedQualifying = bookmarks.filter(b => b && qualifyingIds.includes(b.policy_section_id));
// Single CP (1.0): User bookmarked the correct 2nd-grade homework time guidelines section with a 30-minute limit
checkpoints.push({ passed: bookmarkedQualifying.length >= 1, weight: 1.0 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const supplyItems = JSON.parse(localStorage.getItem('supply_items') || '[]');
const checklists = JSON.parse(localStorage.getItem('supply_checklists') || '[]');
const checklistItems = JSON.parse(localStorage.getItem('supply_checklist_items') || '[]');
const optionalItems = supplyItems.filter(i => {
  if (!i) return false;
  if (i.grade_level !== 'second_grade') return false;
  if (i.is_required) return false;
  if (typeof i.estimated_cost !== 'number') return false;
  return i.estimated_cost <= 5.0;
});
optionalItems.sort((a, b) => {
  const costDiff = (a.estimated_cost || 0) - (b.estimated_cost || 0);
  if (costDiff !== 0) return costDiff;
  const na = (a.name || '').toLowerCase();
  const nb = (b.name || '').toLowerCase();
  if (na < nb) return -1;
  if (na > nb) return 1;
  return 0;
});
const targetItems = optionalItems.slice(0, 4);
let qualifyingCount = 0;
if (targetItems.length > 0) {
  const secondGradeChecklist = checklists.find(cl => cl && cl.grade_level === 'second_grade');
  if (secondGradeChecklist) {
    const clItems = checklistItems.filter(ci => ci && ci.supply_checklist_id === secondGradeChecklist.id);
    const targetIds = targetItems.map(i => i.id);
    const foundTargetIds = targetIds.filter(id => clItems.some(ci => ci.supply_item_id === id));
    qualifyingCount = foundTargetIds.length;
  }
}
// CP1-4: Credit for adding 1, 2, 3, and all 4 of the cheapest qualifying optional items
checkpoints.push({ passed: targetItems.length >= 1 && qualifyingCount >= 1, weight: 0.25 });
checkpoints.push({ passed: targetItems.length >= 2 && qualifyingCount >= 2, weight: 0.25 });
checkpoints.push({ passed: targetItems.length >= 3 && qualifyingCount >= 3, weight: 0.25 });
checkpoints.push({ passed: targetItems.length >= 4 && qualifyingCount >= 4, weight: 0.25 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const sessions = JSON.parse(localStorage.getItem('summer_camp_sessions') || '[]');
const submissions = JSON.parse(localStorage.getItem('camp_interest_submissions') || '[]');
const qualifyingSessions = sessions.filter(s => {
  if (!s || !s.is_active) return false;
  if (s.month !== 'july') return false;
  if (s.daily_start_time !== '9:00 AM') return false;
  if (s.daily_end_time !== '3:00 PM') return false;
  if (typeof s.weekly_fee !== 'number') return false;
  return s.weekly_fee <= 150;
});
qualifyingSessions.sort((a, b) => new Date(a.start_date).getTime() - new Date(b.start_date).getTime());
const targetSession = qualifyingSessions[0] || null;
let hasSubmissionForTarget = false;
if (targetSession) {
  const subsForTarget = submissions.filter(sub => sub && sub.camp_session_id === targetSession.id);
  hasSubmissionForTarget = subsForTarget.length >= 1;
}
// Single CP (1.0): User submitted at least one interest form for the earliest qualifying July 9–3 camp under $150/week
checkpoints.push({ passed: hasSubmissionForTarget, weight: 1.0 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
